SELECT scheme_name
FROM pension_fund_schemes
WHERE scheme_performance_rating > 3;

SELECT MAX(nav) AS max_nav
FROM pension_fund_schemes
WHERE pfm_id = 0;

SELECT pfm_name, pfm_established_date
FROM pension_fund_managers
ORDER BY pfm_established_date ASC;

SELECT scheme_name
FROM pension_fund_schemes
WHERE scheme_id = 1;

SELECT pfm_name
FROM pension_fund_managers
WHERE pfm_id = 0;

SELECT pfm_id, COUNT(scheme_id) AS scheme_count
FROM pension_fund_schemes
GROUP BY pfm_id;
